// App.tsx – Πόση ώρα θα σου πάρει να βρεις την έδρα
import React, { useState, useEffect } from "react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  LabelList,
  Cell,
  ReferenceLine,
} from "recharts";

interface Force {
  name: string;
  votes: number;
  isWhite?: boolean;
}
interface Result extends Force {
  fullSeats: number;
  finalSeats: number;
  remainder: number;
}

const App: React.FC = () => {
  const [forces, setForces] = useState<Force[]>([
    { name: "ΠΑΣΠ", votes: 180 },
    { name: "ΚΚΕ", votes: 155 },
    { name: "ΕΑΑΚ", votes: 110 },
    { name: "ΑΡΑΝ", votes: 22 },
    { name: "ΝΑΡ", votes: 11 },
    { name: "ΔΑΠ", votes: 27 },
    { name: "ΣΣΠ", votes: 3 },
    { name: "Δίκτυο", votes: 0 },
    { name: "Λευκά", votes: 7, isWhite: true },
  ]);
  const [totalSeats, setTotalSeats] = useState<number>(7);
  const [invalidVotes, setInvalidVotes] = useState<number>(0);
  const [roundUp, setRoundUp] = useState<boolean>(false);
  const [dirty, setDirty] = useState<boolean>(false);
  const [configCode, setConfigCode] = useState<string>("");

  // Quota calculation
  const totalValidVotes = forces.reduce((sum, f) => sum + f.votes, 0);
  const rawQuota = totalValidVotes / totalSeats || 0;
  const quota = roundUp ? Math.ceil(rawQuota) : Math.floor(rawQuota);

  const [finalResults, setFinalResults] = useState<Result[]>([]);
  const [seatLog, setSeatLog] = useState<string[]>([]);
  const [nextKoutsi, setNextKoutsi] = useState<string | null>(null);
  const [nextRemainder, setNextRemainder] = useState<number>(0);

  // State code serialization
  useEffect(() => {
    const data = { seats: totalSeats, invalid: invalidVotes, roundUp, forces };
    try {
      const encoded = btoa(unescape(encodeURIComponent(JSON.stringify(data))));
      setConfigCode(encoded);
    } catch {}
  }, [forces, totalSeats, invalidVotes, roundUp]);

  // Seat allocation logic
  useEffect(() => {
    if (dirty) return;
    let temp: Result[] = forces
      .filter((f) => !f.isWhite)
      .map((f) => {
        const fullSeats = Math.floor(f.votes / (quota || 1));
        const remainder = f.votes - fullSeats * (quota || 1);
        return { ...f, fullSeats, finalSeats: fullSeats, remainder };
      });
    const log: string[] = [];
    const allocated = temp.reduce((s, r) => s + r.fullSeats, 0);
    let remaining = totalSeats - allocated;
    for (let i = 0; i < remaining; i++) {
      temp.sort((a, b) => b.remainder - a.remainder || b.votes - a.votes);
      const sel = temp[0];
      log.push(
        `Κουτσή έδρα #${i + 1} ➜ ${sel.name} (υπόλοιπο ${sel.remainder})`
      );
      sel.finalSeats++;
      sel.remainder = 0;
    }
    // Next koutsi
    temp.sort((a, b) => b.remainder - a.remainder || b.votes - a.votes);
    if (temp[0]?.remainder! > 0) {
      setNextKoutsi(temp[0].name);
      setNextRemainder(temp[0].remainder);
    } else {
      setNextKoutsi(null);
      setNextRemainder(0);
    }
    // Final sort by votes
    temp.sort((a, b) => b.votes - a.votes);
    setFinalResults(temp);
    setSeatLog(log);
  }, [forces, totalSeats, invalidVotes, roundUp, quota]);

  const COLORS = [
    "#f58231",
    "#3cb44b",
    "#e6194b",
    "#ffb6c1",
    "#4363d8",
    "#911eb4",
    "#46f0f0",
    "#aaaaaa",
  ];

  return (
    <div className="p-2 min-h-screen bg-gray-50">
      <h1 className="text-xl font-bold mb-4 text-center">
        Πόση ώρα θα σου πάρει να βρεις την έδρα
      </h1>

      {/* Inputs and controls */}
      <div className="bg-white p-4 rounded shadow mb-4 space-y-4">
        {/* Manual forces input */}
        {forces.map((f, i) => (
          <div key={i} className="flex items-center gap-2">
            <input
              className="flex-1 border p-2"
              value={f.name}
              onChange={(e) => {
                setDirty(false);
                const upd = [...forces];
                upd[i].name = e.target.value;
                setForces(upd);
              }}
            />
            <button
              className="px-3 py-1 bg-red-500 text-white rounded disabled:bg-gray-300"
              disabled={f.votes === 0}
              onClick={() => {
                setDirty(false);
                const upd = [...forces];
                upd[i].votes = Math.max(0, upd[i].votes - 1);
                setForces(upd);
              }}
            >
              –
            </button>
            <input
              className="w-16 border p-2 text-center"
              type="number"
              value={f.votes}
              onChange={(e) => {
                setDirty(true);
                const v = parseInt(e.target.value) || 0;
                const upd = [...forces];
                upd[i].votes = v;
                setForces(upd);
              }}
            />
            <button
              className="px-3 py-1 bg-green-500 text-white rounded"
              onClick={() => {
                setDirty(false);
                const upd = [...forces];
                upd[i].votes++;
                setForces(upd);
              }}
            >
              +
            </button>
          </div>
        ))}
        {/* Reset button */}
        <div className="flex justify-end">
          <button
            onClick={() => setForces(forces.map((f) => ({ ...f, votes: 0 })))}
            className="px-4 py-2 bg-red-600 text-white rounded"
          >
            Reset Ψήφων
          </button>
        </div>

        {/* Settings and distribution */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="space-y-2">
            <div className="flex gap-2">
              <label className="w-24">Έδρες:</label>
              <input
                className="flex-1 border p-2"
                type="number"
                value={totalSeats}
                onChange={(e) =>
                  setTotalSeats(Math.max(1, parseInt(e.target.value) || 1))
                }
              />
            </div>
            <div className="flex gap-2">
              <label className="w-24">Άκυρα:</label>
              <input
                className="flex-1 border p-2"
                type="number"
                value={invalidVotes}
                onChange={(e) =>
                  setInvalidVotes(Math.max(0, parseInt(e.target.value) || 0))
                }
              />
            </div>
            <div className="flex gap-2">
              <label className="w-24">Στρογγυλ. Μέτρου:</label>
              <select
                className="flex-1 border p-2"
                value={roundUp ? "up" : "down"}
                onChange={(e) => setRoundUp(e.target.value === "up")}
              >
                <option value="down">Κάτω</option>
                <option value="up">Πάνω</option>
              </select>
            </div>
            <div className="flex gap-2">
              <label className="w-24">Μέτρο:</label>
              <div className="flex-1 border p-2 text-center">{quota}</div>
            </div>
          </div>
          <div className="bg-gray-100 p-2 rounded">
            <h3 className="font-semibold mb-2">Κατανομή Κουτσών Εδρών:</h3>
            {seatLog.map((line, idx) => (
              <p key={idx} className="text-sm">
                {line}
              </p>
            ))}
            <p className="font-semibold mt-2">
              Επόμενος:{" "}
              {nextKoutsi
                ? `${nextKoutsi} (υπόλοιπο ${nextRemainder})`
                : "Κανένας"}
            </p>
          </div>
        </div>
      </div>

      {/* Chart */}
      <div className="bg-white p-4 rounded shadow mb-4">
        <ResponsiveContainer width="100%" height={250}>
          <BarChart
            data={finalResults}
            layout="vertical"
            margin={{ left: 60 }}
            barCategoryGap={0}
          >
            <XAxis type="number" allowDecimals={false} />
            <YAxis type="category" dataKey="name" />
            <Tooltip />
            {[...Array(Math.floor(totalValidVotes / quota || 0))].map(
              (_, i) => (
                <ReferenceLine
                  key={i}
                  x={(i + 1) * quota}
                  stroke="#666"
                  strokeWidth={1}
                />
              )
            )}
            <Bar dataKey="votes" barSize={24}>
              <LabelList
                position="insideLeft"
                content={({
                  x = 0,
                  y = 0,
                  width = 0,
                  height = 0,
                  index = 0,
                }) => {
                  const e = finalResults[index];
                  const rem =
                    e.votes - Math.floor(e.votes / (quota || 1)) * (quota || 1);
                  const isLast =
                    seatLog.length > 0 &&
                    e.name === seatLog[seatLog.length - 1].split("➜ ")[1];
                  return (
                    <>
                      <text
                        x={x + 5}
                        y={y + height / 2}
                        fill="#fff"
                        fontSize={12}
                        fontWeight="bold"
                        dominantBaseline="middle"
                      >
                        {`${e.name} - ${e.votes} - ${e.finalSeats} - [${rem}]`}
                      </text>
                      {isLast && (
                        <text
                          x={x + width + 5}
                          y={y + height / 2}
                          fill="#000"
                          fontSize={14}
                          fontWeight="bold"
                          dominantBaseline="middle"
                        >
                          ΚΟΥΤΣΗ
                        </text>
                      )}
                    </>
                  );
                }}
              />
              {finalResults.map((_, i) => (
                <Cell key={i} fill={COLORS[i % COLORS.length]} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Status Code */}
      <div className="bg-white p-4 rounded shadow">
        <label className="block font-semibold mb-1">Κωδικός Κατάστασης</label>
        <div className="flex gap-2">
          <input
            className="flex-1 border p-2 font-mono"
            value={configCode}
            onChange={(e) => {
              try {
                const d = JSON.parse(
                  decodeURIComponent(escape(atob(e.target.value)))
                );
                setTotalSeats(d.seats);
                setInvalidVotes(d.invalid);
                setRoundUp(d.roundUp);
                setForces(d.forces);
                setDirty(false);
              } catch {}
            }}
          />
          <button
            onClick={() => navigator.clipboard.writeText(configCode)}
            className="px-3 py-1 bg-gray-200 rounded"
          >
            Αντιγραφή
          </button>
          <button
            onClick={async () => {
              try {
                const t = await navigator.clipboard.readText();
                const d = JSON.parse(decodeURIComponent(escape(atob(t))));
                setTotalSeats(d.seats);
                setInvalidVotes(d.invalid);
                setRoundUp(d.roundUp);
                setForces(d.forces);
                setDirty(false);
              } catch {
                alert("Μη έγκυρος κωδικός");
              }
            }}
            className="px-3 py-1 bg-gray-200 rounded"
          >
            Επικόλληση
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;
